def has_digit_one(n):
    """Check if the number contains at least one digit that is a 1."""
    return '1' in str(n)

def find_nth_term(n):
    """Find the nth term of the sequence that consists of all positive multiples of 3 that contain at least one digit that is a 1."""
    i = 12  # Starting from the first term which is 12
    while True:
